def find_word_in_board(board, word):
    rows = len(board)
    if rows == 0:
        return False
    cols = len(board[0])
    if cols == 0:
        return False
    if not word:
        return False

    word_len = len(word)

    directions = [
        (0, 1), (0, -1),  # Horizontal
        (1, 0), (-1, 0),  # Vertical
        (1, 1), (1, -1),  # Diagonal
        (-1, 1), (-1, -1) # Anti-Diagonal
    ]

    def _check_direction(r_start, c_start, dr, dc):
        for i in range(word_len):
            current_r = r_start + i * dr
            current_c = c_start + i * dc

            if not (0 <= current_r < rows and 0 <= current_c < cols):
                return False

            if board[current_r][current_c] != word[i]:
                return False
        return True

    for r in range(rows):
        for c in range(cols):
            if board[r][c] == word[0]:
                for dr, dc in directions:
                    if _check_direction(r, c, dr, dc):
                        return True

    return False
